$pdo=obtenerConexion();$tag='stripecap_'.bin2hex(random_bytes(4));$ids=[];$paths=[];$assert=function(bool$c,string$m)use(&$checks){$checks[$m]=$c;if(!$c)throw new RuntimeException('FALLO: '.$m);};$checks=[];
