finalizarCompraStripe($session,$u,'evt_'.$tag,'checkout.session.completed',$obj);finalizarCompraStripe($session,$u,'evt_'.$tag,'checkout.session.completed',$obj);$q=$pdo->prepare('SELECT * FROM capacitacion_comprobante_documentos WHERE pago_id=:p');$q->execute(['p'=>$pago]);$d=$q->fetch();$pdf=$d?rutaDocumentoCapacitacionAtenea($d,'pdf'):null;$json=$d?rutaDocumentoCapacitacionAtenea($d,'json'):null;$paths=array_filter([$pdf,$json]);$data=$json?json_decode((string)file_get_contents($json),true,512,JSON_THROW_ON_ERROR):[];$assert((int)$pdo->query('SELECT COUNT(*) FROM inscripciones_capacitacion WHERE pago_id='.$pago)->fetchColumn()===1,'inscripción única');$assert((int)$pdo->query('SELECT COUNT(*) FROM capacitacion_comprobante_documentos WHERE pago_id='.$pago)->fetchColumn()===1,'documentos únicos');$assert($pdf&&file_get_contents($pdf,false,null,0,5)==='%PDF-','PDF binario');$assert(($data['documento']['valido_fiscalmente']??null)===false,'JSON no fiscal');$assert((float)($data['totales']['total']??0)===45.25,'total exacto');$assert((int)$pdo->query("SELECT COUNT(*) FROM correo_envios WHERE idempotency_key='compra-confirmada:capacitacion:{$pago}'")->fetchColumn()===1,'correo único');echo json_encode(['pago_id'=>$pago,'checks'=>$checks,'resultado'=>'OK'],JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE).PHP_EOL;
}finally{try{foreach($paths as$p)if(is_file($p))unlink($p);if(!empty($ids['pago'])){$pdo->prepare('DELETE FROM capacitacion_comprobante_documentos WHERE pago_id=?')->execute([$ids['pago']]);$pdo->prepare("DELETE FROM correo_envios WHERE idempotency_key IN (?,?)")->execute(['compra-confirmada:capacitacion:'.$ids['pago'],'capacitacion:asignacion:'.$ids['pago']]);$pdo->prepare('DELETE FROM inscripcion_movimientos WHERE inscripcion_id IN(SELECT id FROM inscripciones_capacitacion WHERE pago_id=?)')->execute([$ids['pago']]);$pdo->prepare('DELETE FROM inscripciones_capacitacion WHERE pago_id=?')->execute([$ids['pago']]);$pdo->prepare('DELETE FROM capacitacion_pagos WHERE id=?')->execute([$ids['pago']]);}$pdo->prepare('DELETE FROM stripe_eventos WHERE stripe_event_id=?')->execute(['evt_'.$tag]);if(!empty($ids['cap']))$pdo->prepare('DELETE FROM asignaturas WHERE id=?')->execute([$ids['cap']]);if(!empty($ids['u'])){$pdo->prepare('DELETE FROM admin_notices WHERE user_id=?')->execute([$ids['u']]);$pdo->prepare('DELETE FROM usuarios WHERE id=?')->execute([$ids['u']]);}}catch(Throwable$e){fwrite(STDERR,'Limpieza: '.$e->getMessage().PHP_EOL);}}
